    'grouparray': { name: 'groupArray', description: 'Creates an array of argument values.', signature: 'groupArray([max_size])(x)', example: 'SELECT groupArray(3)(number) FROM numbers(10)', insertText: 'groupArray(${1:max_size})(${2:column})', category: 'aggregate', returnType: 'Array(T)' },
    'groupuniqarray': { name: 'groupUniqArray', description: 'Creates an array of unique argument values.', signature: 'groupUniqArray([max_size])(x)', example: 'SELECT groupUniqArray(status) FROM events', insertText: 'groupUniqArray(${1:column})', category: 'aggregate', returnType: 'Array(T)' },
    'uniq': { name: 'uniq', description: 'Calculates the approximate number of different argument values.', signature: 'uniq(x[, ...])', example: 'SELECT uniq(user_id) FROM events', insertText: 'uniq(${1:column})', category: 'aggregate', returnType: 'UInt64' },
    'uniqexact': { name: 'uniqExact', description: 'Calculates the exact number of different argument values.', signature: 'uniqExact(x[, ...])', example: 'SELECT uniqExact(user_id) FROM events', insertText: 'uniqExact(${1:column})', category: 'aggregate', returnType: 'UInt64' },
    'uniqcombined': { name: 'uniqCombined', description: 'Calculates the approximate number of different argument values using the HyperLogLog algorithm.', signature: 'uniqCombined(x[, ...])', example: 'SELECT uniqCombined(user_id) FROM events', insertText: 'uniqCombined(${1:column})', category: 'aggregate', returnType: 'UInt64' },
    'argmin': { name: 'argMin', description: 'Calculates the arg value for a minimum val value.', signature: 'argMin(arg, val)', example: 'SELECT argMin(url, event_time) FROM events GROUP BY session_id', insertText: 'argMin(${1:arg}, ${2:val})', category: 'aggregate', returnType: 'Same as arg' },
