    'topk': { name: 'topK', description: 'Returns an array of the approximately most frequent values.', signature: 'topK(N)(column)', example: 'SELECT topK(5)(user_id) FROM events', insertText: 'topK(${1:5})(${2:column})', category: 'aggregate', returnType: 'Array(T)' },
