    'quantile': { name: 'quantile', description: 'Computes an approximate quantile of a numeric data sequence.', signature: 'quantile(level)(x)', example: 'SELECT quantile(0.95)(response_time) FROM requests', insertText: 'quantile(${1:0.95})(${2:column})', category: 'aggregate', returnType: 'Float64' },
    'quantiles': { name: 'quantiles', description: 'Computes multiple approximate quantiles.', signature: 'quantiles(level1, ...)(x)', example: 'SELECT quantiles(0.5, 0.9, 0.99)(response_time) FROM requests', insertText: 'quantiles(${1:0.5}, ${2:0.95})(${3:column})', category: 'aggregate', returnType: 'Array(Float64)' },
