    'windowfunnel': { name: 'windowFunnel', description: 'Searches for event chains in a sliding time window.', signature: 'windowFunnel(window)(timestamp, cond1, cond2, ...)', example: "SELECT windowFunnel(86400)(event_time, event = 'view', event = 'cart', event = 'purchase') FROM user_events GROUP BY user_id", insertText: "windowFunnel(${1:86400})(${2:event_time}, ${3:cond1}, ${4:cond2})", category: 'aggregate', returnType: 'UInt8' },
