    'sequencematch': { name: 'sequenceMatch', description: 'Checks whether the sequence contains an event chain that matches the pattern.', signature: "sequenceMatch(pattern)(timestamp, cond1, cond2, ...)", example: "SELECT sequenceMatch('(?1)(?2)')(event_time, event = 'login', event = 'purchase') FROM events GROUP BY user_id", insertText: "sequenceMatch('${1:(?1)(?2)}')(${2:event_time}, ${3:cond1}, ${4:cond2})", category: 'aggregate', returnType: 'UInt8' },
    'sequencecount': { name: 'sequenceCount', description: 'Counts the number of event chains that match the pattern.', signature: "sequenceCount(pattern)(timestamp, cond1, cond2, ...)", example: "SELECT sequenceCount('(?1)(?2)')(event_time, event = 'view', event = 'purchase') FROM events GROUP BY user_id", insertText: "sequenceCount('${1:(?1)(?2)}')(${2:event_time}, ${3:cond1}, ${4:cond2})", category: 'aggregate', returnType: 'UInt64' },

